import * as styles from '../SegmentSelector.sty.js';

/** @internal */
export const SegmentsOverlay = ({ labelId }: { labelId: string }) => {
  const { getAllSegments } = useSegmentsCache();
  const { data, isLoading } = useQuery(
    {
      queryKey: ['getAllSegments'],
      queryFn: () => getAllSegments().catch(() => new Map()),
      notifyOnChangeProps: ['dataUpdatedAt'],
      throwOnError: false,
    },
    segmentsClient.queryClient,
  );

  const { isLoading: isLoadingPresets } = useQuery(
    {
      queryKey: ['getSegmentsPresets'],
      queryFn: () =>
        // We don't want to render the error fallback in case the presets are not available.
        // However, we sill want to keep the loading state until both queries are resolved.
        getSegmentsPresets().catch(() => {
          return {
            pinnedPresets: [],
            recentPresets: [],
          };
        }),
    },
    segmentsClient.queryClient,
  );

  if (isLoading || isLoadingPresets) {
    return <LoadingSegments />;
  }

  return <SegmentsContent cachedSegments={data ?? new Map()} id={labelId} />;
};

type SegmentsContentProps = {
  cachedSegments: Map<string, CachedSegment>;
  id: string;
};

async function applySegments(
  uiSegments: SegmentSelectorUIState['uiSegments'],
  setSegments: (segments: QueryFilterSegment[]) => Promise<void>,
  overlayState?: OverlayTriggerState,
) {
  try {
    const applicableSegments = await Promise.all(
      uiSegments
        .filter((uiSegment) => !uiSegment.isPlaceholder)
        .map(async (uiSegment) => {
          const errorKey = await getErrorKey(uiSegment);

          if (errorKey === 'needs-update') {
            return {
              id: uiSegment.id,
            };
          }

          return {
            id: uiSegment.id,
            variables: uiSegment.variables,
          };
        }),
    );

    await setSegments(applicableSegments);
    const isValid = await areUiSegmentsValid(applicableSegments);

    if (isValid) {
      overlayState?.close();
    }
  } catch {
    /** we don't want to log the error again. */
  }
}

/**
 * SegmentsManager-component for the SegmentSelector Overlay
 * @internal
 */
const SegmentsContent = ({ cachedSegments, id }: SegmentsContentProps) => {
  const { dispatch, overlayState } = useContext(UISegmentsDispatchContext);
  const { dispatch: parentErrorDispatch } = useFormFieldMessagesContext();

  const intl = useIntl();
  const addButtonRef = useRef<null | HTMLButtonElement>(null);
  const {
    uiSegments,
    hasSelection,
    readOnly,
    focusedSegmentId,
    arrayIdentifierErrorIds,
  } = useContext(UISegmentsContext);

  const formId = useId();
  const formRef = useRef<HTMLFormElement | null>(null);

  useEffect(() => {
    const errorIds = arrayIdentifierErrorIds;

    // We only want to show the error once the overlay closes to be consistent in the validation flow.
    return () => {
      if (!errorIds) {
        return;
      }

      if (errorIds.length > 0) {
        parentErrorDispatch?.({
          type: FormFieldMessagesAction.ADDMESSAGE,
          payload: {
            id: 'array-identifier',
            validityStateKey: 'customError',
            variant: 'error',
            messageType: 'formcontrol',
            message: (
              <FormattedMessage
                {...SEGMENTSELECTOR_MESSAGES.arrayIdentifierError}
              />
            ),
          },
        });
        return;
      }

      parentErrorDispatch?.({
        type: FormFieldMessagesAction.REMOVEMESSAGE,
        payload: {
          id: 'array-identifier',
          messageType: 'formcontrol',
        },
      });
    };
  }, [arrayIdentifierErrorIds]);

  const availableSegments = useMemo(() => {
    const tmp: CachedSegment['segment'][] = [];
    cachedSegments.forEach((value, key) => {
      // Remove all the segments that have already been selected or are private
      if (
        !value.temporarilyApplied &&
        !uiSegments.some((segment) => segment.id === key)
      ) {
        tmp.push({ ...value.segment });
      }
    });

    return tmp.sort((firstSegment, secondSegment) =>
      firstSegment.name.localeCompare(secondSegment.name),
    );
  }, [cachedSegments, uiSegments]);

  const {
    segments,
    removeAllSegments: removeAllSegmentsFromStore,
    setSegments,
  } = useSegments();
  const { removeAllUISegments, clearPlaceholder } = useSegmentsUIContext();

  if (segments.length === 0 && cachedSegments.size === 0) {
    return <EmptySegments />;
  }

  // If the segmentsClient has no access rights, we want to rely on the trigger's validity state.
  const MessageWrapper = segmentsClient.hasAccessRights
    ? FormFieldMessageContextProvider
    : Fragment;

  return (
    <Flex
      px={4}
      pb={8}
      gap={0}
      flexDirection="column"
      id={id}
      width="100vw"
      className={overlayStyles.overlayDefaultWidth}
    >
      <div className={overlayStyles.scrollContainer}>
        <Grid
          as="form"
          ref={formRef}
          id={formId}
          px={12}
          pt={12}
          pb={16}
          onInvalid={(event: ReactFormEvent) => {
            event.stopPropagation();

            if (
              (event.nativeEvent.target as HTMLSelectElement).validity
                .customError &&
              !(event.nativeEvent.target as HTMLSelectElement).validity
                .valueMissing
            ) {
              applySegments(uiSegments, setSegments, overlayState).catch(
                () => undefined,
              );
            }
          }}
          onSubmit={(event: ReactFormEvent) => {
            event.preventDefault();
            event.stopPropagation();

            applySegments(uiSegments, setSegments, overlayState).catch(
              () => undefined,
            );
          }}
          onKeyDown={(event: ReactKeyboardEvent) => {
            // Enables form submission on cmd/strg + enter
            if (event.key === 'Enter' && (event.ctrlKey || event.metaKey)) {
              // Fires an submit as if triggered via the submit button and, therefore, triggers validation as well.
              formRef?.current?.requestSubmit();
            }
          }}
        >
          <FieldSet className={overlayStyles.fieldSet}>
            <FieldSet.Legend className={overlayStyles.legend}>
              {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.legend)}
            </FieldSet.Legend>
            <ul className={styles.segmentSelectorList}>
              {uiSegments?.map((segment) => (
                <MessageWrapper key={segment.id}>
                  {/** ^ We don't want the outside error message influence the inside error messages and vice versa. */}
                  <SelectionBar
                    key={segment.id}
                    uiSegment={segment}
                    segment={cachedSegments.get(segment.id)}
                    readOnly={readOnly}
                    availableSegments={availableSegments}
                    clearable={
                      segment.isPlaceholder ? uiSegments.length > 1 : true
                    }
                    autoFocus={segment.id === focusedSegmentId}
                    returnFocusTo={addButtonRef}
                  />
                </MessageWrapper>
              ))}
            </ul>
            {!readOnly &&
              hasSelection &&
              segmentsClient.hasAccessRights !== false && (
                <Grid gridTemplateColumns="1fr auto auto">
                  <Button
                    onClick={() =>
                      dispatch({
                        type: 'add',
                        payload: { isPlaceholder: true },
                      })
                    }
                    variant="emphasized"
                    ref={addButtonRef}
                    data-dt-name="Add"
                  >
                    <Button.Prefix
                      aria-label={intl.formatMessage(
                        SEGMENTSELECTOR_MESSAGES.addSegment,
                      )}
                    >
                      <PlusIcon />
                    </Button.Prefix>
                    Segment
                  </Button>
                  <Button
                    onClick={() => {
                      removeAllSegmentsFromStore();
                      removeAllUISegments();
                      overlayState?.close();
                    }}
                    type="reset"
                    form={formId}
                    data-dt-name="ClearAll"
                  >
                    {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.clearAll)}
                  </Button>
                  <Button
                    type="submit"
                    form={formId}
                    color="primary"
                    variant="accent"
                    data-dt-name="Apply"
                    onClick={() => clearPlaceholder()}
                  >
                    {intl.formatMessage(SEGMENTSELECTOR_MESSAGES.applyButton)}
                  </Button>
                </Grid>
              )}
          </FieldSet>
          {segmentsClient.hasAccessRights === false && (
            <NoAccessHint readOnly={readOnly} />
          )}
        </Grid>
        {!readOnly && segmentsClient.hasAccessRights === true && (
          <SegmentsPresetList showDivider={hasSelection} />
        )}
      </div>
      <Divider />
      <SegmentFooter />
    </Flex>
  );
};
